prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?task ?taskName ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4ccc3fd711004f519782ac92e58f6ddd" ;
         bbo:name ?modelName .
  ?choreo tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Informieren über Zustimmung")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?idField ?idValue WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName .

  {
    ?model tai:originalId ?idValue .
    BIND("originalId" AS ?idField)
  }
  UNION
  {
    ?model tai:normalizedId ?idValue .
    BIND("normalizedId" AS ?idField)
  }
  UNION
  {
    ?model tai:organizationId ?idValue .
    BIND("organizationId" AS ?idField)
  }

  FILTER(CONTAINS(STR(?idValue), "4ccc3fd711004f519782ac92e58f6ddd"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?task ?taskName ?reachable WHERE {
  {
    SELECT DISTINCT ?choreo ?task ?taskName WHERE {
      ?model a bboExt:Model ;
             tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
             tai:belongsTo ?org .
      ?choreo tai:belongsTo ?model .

      ?task a bboExt:ChoreographyTask ;
            bbo:name ?taskName ;
            tai:belongsTo ?choreo .
      FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Informieren über Zustimmung")))
    }
    LIMIT 25
  }

  ?start a bboExt:StartEvent ;
          tai:belongsTo ?choreo ;
          bbo:name ?startName .

  BIND(EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  } AS ?reachable)
}
ORDER BY DESC(?reachable) ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
         tai:belongsTo ?org .
  ?choreo tai:belongsTo ?model .
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .
  FILTER(BOUND(?taskName))
}
ORDER BY LCASE(STR(?taskName))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
         bbo:name ?modelName .

  ?choreo tai:belongsTo ?model .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?type ?name WHERE {
  ?choreo tai:belongsTo ?model .
  {
    SELECT DISTINCT ?choreo ?model WHERE {
      ?model a bboExt:Model ;
             tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
      ?choreo tai:belongsTo ?model .
    }
  }

  ?edge a bbo:SequenceFlow ;
        tai:belongsTo ?choreo ;
        bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .

  BIND(?src AS ?node)
  OPTIONAL { ?node a ?type . }
  OPTIONAL { ?node bbo:name ?name . }

} LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?src ?srcName ?tgt ?tgtName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
         tai:belongsTo ?org .

  ?src tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .
  ?tgt tai:belongsTo ?choreo .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .

  OPTIONAL { ?src bbo:name ?srcName . }
  OPTIONAL { ?tgt bbo:name ?tgtName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?node) AS ?nodeCount) (COUNT(DISTINCT ?edge) AS ?edgeCount) WHERE {
  {
    SELECT DISTINCT ?node WHERE {
      ?node tai:belongsTo ?choreo .
      ?choreo tai:belongsTo ?model .
      ?model a bboExt:Model ; tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
    }
  }
  OPTIONAL {
    ?edge a bbo:SequenceFlow ;
          bbo:has_sourceRef ?src ;
          bbo:has_targetRef ?tgt .
    FILTER EXISTS {
      ?src tai:belongsTo ?ch1 .
      ?ch1 tai:belongsTo ?m1 .
      ?m1 tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
    }
    FILTER EXISTS {
      ?tgt tai:belongsTo ?ch2 .
      ?ch2 tai:belongsTo ?m2 .
      ?m2 tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
    }
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?elem) AS ?elemCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?elem tai:belongsTo ?model .
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?definitions ?defType WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  {
    ?definitions tai:belongsTo ?model .
    BIND("definitions" AS ?defType)
  }
}LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?nodeType ?nodeName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?edge a bbo:SequenceFlow ;
        tai:belongsTo ?choreo ;
        bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .

  VALUES ?node { ?src ?tgt }
  OPTIONAL { ?node a ?nodeType . }
  OPTIONAL { ?node bbo:name ?nodeName . }
  FILTER(BOUND(?nodeName) && STRLEN(STR(?nodeName)) > 0)
}
ORDER BY LCASE(STR(?nodeName))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?nodeType ?nodeName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  {
    SELECT DISTINCT ?src as ?node WHERE {
      ?edge a bbo:SequenceFlow ;
            tai:belongsTo ?choreo ;
            bbo:has_sourceRef ?src .
    }
  }
  UNION
  {
    SELECT DISTINCT ?tgt as ?node WHERE {
      ?edge a bbo:SequenceFlow ;
            tai:belongsTo ?choreo ;
            bbo:has_targetRef ?tgt .
    }
  }

  OPTIONAL { ?node a ?nodeType . }
  OPTIONAL { ?node bbo:name ?nodeName . }
  FILTER(BOUND(?nodeName) && STRLEN(STR(?nodeName)) > 0)
}
ORDER BY LCASE(STR(?nodeName))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?nodeType ?nodeName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  { 
    SELECT DISTINCT ?src WHERE {
      ?edge a bbo:SequenceFlow ;
            tai:belongsTo ?choreo ;
            bbo:has_sourceRef ?src .
    }
  }
  UNION
  {
    SELECT DISTINCT ?tgt WHERE {
      ?edge a bbo:SequenceFlow ;
            tai:belongsTo ?choreo ;
            bbo:has_targetRef ?tgt .
    }
  }

  BIND( COALESCE(?src, ?tgt) AS ?node )
  OPTIONAL { ?node a ?nodeType . }
  OPTIONAL { ?node bbo:name ?nodeName . }
  FILTER(BOUND(?nodeName) && STRLEN(STR(?nodeName)) > 0)
}
ORDER BY LCASE(STR(?nodeName))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?reachable WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" ;
         tai:belongsTo ?org .

  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Informieren über Zustimmung")))

  {
    SELECT DISTINCT ?task WHERE {
      ?start a bboExt:StartEvent ;
             tai:belongsTo ?choreo .

      FILTER(EXISTS {
        ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
      })
    }
  }

  BIND(true AS ?reachable)
}
LIMIT 25
